-- Codex review hardening for PR #29 (estimate share endpoint).
--
-- Two distinct issues both apply to the same RPCs landed in
-- 20260513110100_estimate_share_snapshots_and_rpcs.sql. Both fixes are
-- redefinitions of the function bodies; the table itself is unchanged.
--
-- P1: publish_estimate_share_snapshot — share_token hijack
--   The previous version only validated that the caller is an owner /
--   co-owner of `p_project_id`, but `ON CONFLICT (share_token) DO UPDATE`
--   rewrote the row's `project_id` unconditionally. That let any owner of
--   any project take over a known share_token of a different project (e.g.
--   one from a public link) and substitute their own snapshot/approval
--   state. We now reject the call when the token already belongs to a
--   different project.
--
-- P2: approve_estimate_version_by_share_token — re-stamping
--   The previous version had no `status` / `approval_stamp` guard, so
--   anyone with the token could repeatedly overwrite an existing approval
--   (name / surname / email / timestamp) after the fact. That destroys the
--   audit trail. Approval is now single-shot: the UPDATE only matches
--   rows that are still `status = 'proposed'` and have a null stamp.

drop function if exists public.approve_estimate_version_by_share_token(text, jsonb);

create function public.approve_estimate_version_by_share_token(
  p_share_token text,
  p_payload jsonb
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_row record;
  v_name text := nullif(trim(coalesce(p_payload->>'name', '')), '');
  v_surname text := nullif(trim(coalesce(p_payload->>'surname', '')), '');
  v_email text := nullif(trim(coalesce(p_payload->>'email', '')), '');
  v_timestamp_text text := p_payload->>'timestamp';
  v_timestamp timestamptz;
begin
  if p_share_token is null or length(p_share_token) = 0 then
    raise exception 'share token is required' using errcode = '22023';
  end if;
  if v_name is null or v_surname is null or v_email is null then
    raise exception 'approval payload must include non-empty name, surname, and email'
      using errcode = '22023';
  end if;

  begin
    v_timestamp := coalesce(v_timestamp_text::timestamptz, now());
  exception when others then
    v_timestamp := now();
  end;

  -- Single-shot approval: once a stamp lands, the row stays immutable.
  -- Without this guard anon callers with the token could rewrite the
  -- stamp after the fact, destroying the audit trail.
  update public.estimate_share_snapshots
  set approval_stamp = jsonb_build_object(
        'name', v_name,
        'surname', v_surname,
        'email', v_email,
        'timestamp', to_char(v_timestamp at time zone 'UTC', 'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"')
      ),
      status = 'approved',
      updated_at = now()
  where share_token = p_share_token
    and submitted = true
    and archived = false
    and share_approval_policy <> 'disabled'
    and status <> 'approved'
    and approval_stamp is null
  returning share_token,
            project_id,
            version_number,
            status,
            share_approval_policy,
            share_approval_disabled_reason,
            snapshot,
            approval_stamp,
            submitted,
            archived,
            created_by,
            created_at,
            updated_at
  into v_row;

  if not found then
    raise exception 'share token not found, archived, already approved, or approval is disabled'
      using errcode = 'P0002';
  end if;

  return to_jsonb(v_row);
end;
$$;

revoke all on function public.approve_estimate_version_by_share_token(text, jsonb) from public;
grant execute on function public.approve_estimate_version_by_share_token(text, jsonb) to anon;
grant execute on function public.approve_estimate_version_by_share_token(text, jsonb) to authenticated;

drop function if exists public.publish_estimate_share_snapshot(uuid, text, integer, jsonb, text, text);

create function public.publish_estimate_share_snapshot(
  p_project_id uuid,
  p_share_token text,
  p_version_number integer,
  p_snapshot jsonb,
  p_share_approval_policy text default 'registered',
  p_share_approval_disabled_reason text default null
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_caller uuid := auth.uid();
  v_row record;
begin
  if v_caller is null then
    raise exception 'authentication required to publish a share snapshot'
      using errcode = '42501';
  end if;
  if p_project_id is null then
    raise exception 'project_id is required' using errcode = '22023';
  end if;
  if p_share_token is null or length(p_share_token) = 0 then
    raise exception 'share_token is required' using errcode = '22023';
  end if;
  if p_version_number is null or p_version_number < 1 then
    raise exception 'version_number must be a positive integer' using errcode = '22023';
  end if;
  if p_snapshot is null then
    raise exception 'snapshot is required' using errcode = '22023';
  end if;
  if p_share_approval_policy is not null
     and p_share_approval_policy not in ('registered', 'disabled') then
    raise exception 'share_approval_policy must be either registered or disabled'
      using errcode = '22023';
  end if;

  if not exists (
    select 1 from public.project_members pm
    where pm.project_id = p_project_id
      and pm.profile_id = v_caller
      and pm.role in ('owner', 'co_owner')
  ) then
    raise exception 'only project owners or co-owners can publish a share snapshot'
      using errcode = '42501';
  end if;

  -- Reject share_token hijack: refuse the call when the token already
  -- belongs to a different project. Without this guard the ON CONFLICT
  -- path rewrote project_id silently, letting any owner of any project
  -- take over a public token from another project's share link.
  if exists (
    select 1 from public.estimate_share_snapshots
    where share_token = p_share_token
      and project_id <> p_project_id
  ) then
    raise exception 'share_token already belongs to a different project'
      using errcode = '42501';
  end if;

  insert into public.estimate_share_snapshots as ess (
    share_token,
    project_id,
    version_number,
    status,
    share_approval_policy,
    share_approval_disabled_reason,
    snapshot,
    submitted,
    archived,
    created_by,
    updated_at
  ) values (
    p_share_token,
    p_project_id,
    p_version_number,
    'proposed',
    coalesce(p_share_approval_policy, 'registered'),
    p_share_approval_disabled_reason,
    p_snapshot,
    true,
    false,
    v_caller,
    now()
  )
  on conflict (share_token) do update set
    project_id = excluded.project_id,
    version_number = excluded.version_number,
    status = 'proposed',
    share_approval_policy = excluded.share_approval_policy,
    share_approval_disabled_reason = excluded.share_approval_disabled_reason,
    snapshot = excluded.snapshot,
    approval_stamp = null,
    submitted = true,
    archived = false,
    updated_at = now()
  returning share_token,
            project_id,
            version_number,
            status,
            share_approval_policy,
            share_approval_disabled_reason,
            snapshot,
            approval_stamp,
            submitted,
            archived,
            created_by,
            created_at,
            updated_at
  into v_row;

  return to_jsonb(v_row);
end;
$$;

revoke all on function public.publish_estimate_share_snapshot(uuid, text, integer, jsonb, text, text) from public;
grant execute on function public.publish_estimate_share_snapshot(uuid, text, integer, jsonb, text, text) to authenticated;
